jQuery(document).ready(function($){var wow=new WOW().init();wow.delay=2000;wow.duration=1000;let html=$('.marquee-text-top').css('margin-right','50px').clone();$('.marquee-top').append(html);$('.marquee-top').marquee({direction:'left',speed:10000,duplicated:!0,pauseOnHover:!0,gap:50,delayBeforeStart:0,});$('.marquee-review-up').marquee({direction:'up',speed:7000,loop:!0,pausehover:!1,spaceBetween:20,});$('.marquee-review-down').marquee({direction:'down',speed:7000,loop:!0,pausehover:!1,spaceBetween:20,});$(".owlkhoahoc > .col-inner").addClass('owl-theme').addClass('owl-carousel').owlCarousel({loop:!0,dots:!1,nav:!1,margin:20,stagePadding:5,navText:['<i class="fa fa-angle-left" aria-hidden="true"></i>','<i class="fa fa-angle-right" aria-hidden="true"></i>'],autoplay:!0,responsive:{100:{items:1,},480:{items:2,},580:{items:4,},768:{items:4,},}});$(".owl-gioithieu > .col-inner").addClass('owl-theme').addClass('owl-carousel').owlCarousel({loop:!0,dots:!1,nav:!0,margin:20,center:!0,stagePadding:0,navText:['<i class="fa fa-angle-left" aria-hidden="true"></i>','<i class="fa fa-angle-right" aria-hidden="true"></i>'],autoplay:!0,responsive:{100:{items:1,},480:{items:2,},580:{items:3,},768:{items:3,},}});$(".wp-item-bangdiem > .col-inner").addClass('owl-theme').addClass('owl-carousel').owlCarousel({loop:!0,dots:!1,nav:!0,margin:15,stagePadding:5,navText:['<i class="fa fa-angle-left" aria-hidden="true"></i>','<i class="fa fa-angle-right" aria-hidden="true"></i>'],autoplay:!0,responsive:{100:{items:1,}}});$('.section-hv-noi-gi .col-inner').each(function(){$(this).find('a').each(function(){$(this).attr('data-fancybox','images');$(this).attr('rel','lightbox')})});function initPaperPlaneEffect(){const $paperPlane=$('#paper-plane');if($paperPlane.length===0){console.log('Paper plane element not found');return}
$paperPlane.css({'position':'fixed','z-index':'9999','transition':'all 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94)','pointer-events':'none'});let lastScrollTop=0;let isAnimating=!1;let animationTimeout;let currentSide='left';let currentHeight=100;function getRandomHeight(){const windowHeight=$(window).height();const planeHeight=$paperPlane.outerHeight();const minHeight=50;const maxHeight=windowHeight-planeHeight-50;return Math.floor(Math.random()*(maxHeight-minHeight+1))+minHeight}
function updatePaperPlanePosition(){if(isAnimating)return;const scrollTop=$(window).scrollTop();const windowHeight=$(window).height();const planeHeight=$paperPlane.outerHeight();const planeWidth=$paperPlane.outerWidth();let newTop=currentHeight;const scrollDirection=scrollTop>lastScrollTop?'down':'up';const scrollSpeed=Math.abs(scrollTop-lastScrollTop);let newLeft;const edgeMargin=20;const leftEdge=edgeMargin;const rightEdge=$(window).width()-planeWidth-edgeMargin;if(scrollSpeed>5){if(scrollDirection==='down'){if(currentSide!=='right'){currentSide='right';currentHeight=getRandomHeight()}
newLeft=rightEdge}else{if(currentSide!=='left'){currentSide='left';currentHeight=getRandomHeight()}
newLeft=leftEdge}}else{if(currentSide==='right'){newLeft=rightEdge}else{newLeft=leftEdge}}
if(Math.random()<0.001){currentHeight=getRandomHeight()}
let rotation=0;if(scrollDirection==='down'&&currentSide==='right'){rotation=Math.min(10,scrollSpeed*0.3)}else if(scrollDirection==='up'&&currentSide==='left'){rotation=Math.max(-10,-scrollSpeed*0.3)}
isAnimating=!0;$paperPlane.css({'top':newTop+'px','left':newLeft+'px','transform':`rotate(${rotation}deg)`});clearTimeout(animationTimeout);animationTimeout=setTimeout(()=>{isAnimating=!1},800);lastScrollTop=scrollTop}
let scrollTimeout;$(window).on('scroll',function(){if(scrollTimeout)return;scrollTimeout=setTimeout(()=>{updatePaperPlanePosition();scrollTimeout=null},16)});currentHeight=getRandomHeight();updatePaperPlanePosition()}
initPaperPlaneEffect()})